class Networking {
    private let environment: Environment
    private var session: URLSession
    
    init(environment: Environment) {
        self.environment = environment
        self.session = URLSession(configuration: .default)
    }
    
    func get(url: String, completion: @escaping (Data?, Error?) -> Void) {
        guard let url = URL(string: "\(environment.baseURL)\(url)") else { return }
        
        var request = URLRequest(url: url)
        request.httpMethod = "GET"
        
        session.dataTask(with: request) { data, error in
            completion(data, error)
        }.resume()
    }
    
    func post(url: String, parameters: [String: Any], completion: @escaping (Data?, Error?) -> Void) {
